-- V20260608_004__ReseedCcodemFromCsv.sql
-- 공통코드(TPRMPP_CCODEM) 전체를 code.csv 기준으로 재적재.
-- IT_PTL_TMN_SVC_TC PK 충돌: '단말기종류'(001~008)만 유지, '단말기용도' 4행 제외(사용자 결정).
-- STT_DTM=2026-01-01, END_DTM=9999-12-31, '[NULL]'->NULL.
-- 멱등성: code.csv가 관리하는 30개 그룹만 DELETE 후 재-INSERT(단일 트랜잭션).
--   ※ 전체 DELETE 금지 — code.csv에 없는 그룹(IT_PTL_BG_PRN_TC, TASK_DBR_RLT_TC, CTT_MANR_C 등
--      별도 마이그레이션이 시드)을 보존하기 위해 대상 그룹을 한정한다.
-- SET DEFINE OFF: 'S&P' 등 '&' 포함 값이 SQL*Plus 치환변수로 해석되는 것을 방지.

SET DEFINE OFF

DELETE FROM ITPAPP.TPRMPP_CCODEM WHERE CO_C_ID IN ('ABUS_TC','APF_PRG_STS_C','BG_RQS','BG_UNT_ABUS_C','BLB_TC','BZ_DTT','CKG_ITM_C','CST_TP_TC','CUR_C','DCD_STS','DFR_CLE_C','DUP_AMT','DUP_IOE','EXE_PTT_YN','INFM_SVC_TC','IOE_C','IT_PTL_EDRT_TC','IT_PTL_RPR_STS_TC','IT_PTL_STS_TC','IT_PTL_TCHN_TP_TC','IT_PTL_TMN_KD_TC','IT_PTL_TMN_SVC_TC','KPN_TC','NAC_TP','PRIT_C','PRJ_TP','SD_TC','SYS_PVC','SYS_RQC','TMN_YN');


COMMIT;
